    flex-direction: column;
    align-items: center;
    padding: 48px 24px 64px;
  }

  /* ── tree container ── */
  .tree {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0;
    width: 100%;
    max-width: 860px;
  }

  /* ── generic node ── */
  .node {
    border-radius: 12px;
    padding: 14px 22px;
    text-align: center;
    position: relative;
    cursor: default;
    transition: transform 0.18s ease, box-shadow 0.18s ease;
  }
  .node:hover { transform: translateY(-2px); }

  .node .label {
    font-size: 14px;
    font-weight: 700;
    letter-spacing: -0.2px;
    line-height: 1.4;
  }
  .node .sub {
    font-size: 11.5px;
    font-weight: 400;
    margin-top: 3px;
    opacity: 0.75;
    line-height: 1.4;
  }

  /* ── root ── */
  .node-root {
    background: linear-gradient(135deg, #3a2f8a 0%, #5a4fd4 100%);
    box-shadow: 0 0 32px rgba(127,119,221,0.25);
    color: #e8e6ff;
    width: 260px;
    border: 1px solid rgba(127,119,221,0.4);
  }
  .node-root .label { font-size: 18px; letter-spacing: 1px; }

  /* ── pillar ── */
  .node-teal {
    background: rgba(29,158,117,0.15);
    border: 1px solid rgba(29,158,117,0.45);
    color: #a8ecd4;
    width: 240px;
  }
  .node-teal .label { color: #c8f5e4; }
  .node-teal .sub   { color: rgba(168,236,212,0.7); }

  .node-amber {
    background: rgba(186,117,23,0.15);
    border: 1px solid rgba(186,117,23,0.45);
    color: #f5d89a;
    width: 240px;
  }
  .node-amber .label { color: #fae3b0; }
  .node-amber .sub   { color: rgba(245,216,154,0.7); }

  /* ── execution items ── */
  .node-exec-teal {
    background: rgba(29,158,117,0.08);
    border: 1px solid rgba(29,158,117,0.3);
    color: #a8ecd4;
    width: 180px;
    border-radius: 10px;
    padding: 12px 16px;
  }
  .node-exec-teal .label { font-size: 13px; color: #c8f5e4; }
  .node-exec-teal .sub   { font-size: 11px; color: rgba(168,236,212,0.65); }

  .node-exec-amber {
    background: rgba(186,117,23,0.08);
    border: 1px solid rgba(186,117,23,0.3);
    color: #f5d89a;
    width: 200px;
    border-radius: 10px;
    padding: 12px 16px;
  }
  .node-exec-amber .label { font-size: 13px; color: #fae3b0; }
  .node-exec-amber .sub   { font-size: 11px; color: rgba(245,216,154,0.65); }

  /* ── goal items ── */
  .node-goal-teal {
    background: rgba(29,158,117,0.06);
    border: 1px dashed rgba(29,158,117,0.45);
    color: #7dd9b5;
    width: 180px;
    border-radius: 10px;
    padding: 12px 16px;
