    background: var(--connector);
    flex-shrink: 0;
  }
  .connector-h {
    height: 1px;
    background: var(--connector);
  }
  .connector-dashed {
    width: 1px;
    background: repeating-linear-gradient(
      to bottom,
      rgba(255,255,255,0.2) 0px,
      rgba(255,255,255,0.2) 5px,
      transparent 5px,
      transparent 9px
    );
    flex-shrink: 0;
  }
  .connector-dashed-teal {
    width: 1px;
    background: repeating-linear-gradient(
      to bottom,
      rgba(29,158,117,0.5) 0px,
      rgba(29,158,117,0.5) 5px,
      transparent 5px,
      transparent 9px
    );
