    width: 1px;
    background: repeating-linear-gradient(
      to bottom,
      rgba(186,117,23,0.5) 0px,
      rgba(186,117,23,0.5) 5px,
      transparent 5px,
      transparent 9px
    );
    flex-shrink: 0;
  }

  /* ── row helpers ── */
  .row {
    display: flex;
    align-items: flex-start;
    justify-content: center;
    gap: 0;
    width: 100%;
  }
  .col {
    display: flex;
    flex-direction: column;
    align-items: center;
  }

  /* ── branch wrapper ── */
  .branch {
    display: flex;
    flex-direction: column;
    align-items: center;
  }

  /* ── pillar section ── */
  .pillar-section {
    display: flex;
    flex-direction: column;
    align-items: center;
  }

  /* ── split row: left tree + right tree ── */
  .two-col {
    display: flex;
    align-items: flex-start;
    justify-content: center;
    gap: 48px;
    width: 100%;
  }

  /* ── half divider line across two trees ── */
  .h-bridge {
    position: relative;
    width: 100%;
    height: 1px;
  }

  /* ── label tag for goal level ── */
  .tag {
    font-size: 10px;
    font-weight: 500;
    letter-spacing: 1px;
    text-transform: uppercase;
    color: var(--text-secondary);
    margin-bottom: 8px;
    opacity: 0.6;
  }

  /* ── fade-in animation ── */
  .tree > * {
    animation: fadeUp 0.4s ease both;
  }
  .tree > *:nth-child(1)  { animation-delay: 0.0s; }
  .tree > *:nth-child(2)  { animation-delay: 0.08s; }
  .tree > *:nth-child(3)  { animation-delay: 0.14s; }
  .tree > *:nth-child(4)  { animation-delay: 0.20s; }
  .tree > *:nth-child(5)  { animation-delay: 0.26s; }
  .tree > *:nth-child(6)  { animation-delay: 0.32s; }
  .tree > *:nth-child(7)  { animation-delay: 0.38s; }
  .tree > *:nth-child(8)  { animation-delay: 0.44s; }
  .tree > *:nth-child(9)  { animation-delay: 0.50s; }
  .tree > *:nth-child(10) { animation-delay: 0.56s; }

  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(10px); }
    to   { opacity: 1; transform: translateY(0); }
  }

  /* ── legend ── */
  .legend {
    display: flex;
    gap: 24px;
    margin-top: 40px;
    font-size: 11px;
    color: var(--text-secondary);
    align-items: center;
    opacity: 0.7;
  }
  .legend-item { display: flex; align-items: center; gap: 8px; }
  .legend-line { width: 24px; height: 1px; background: var(--connector); }
  .legend-line-dashed {
    width: 24px;
    height: 1px;
    background: repeating-linear-gradient(to right,
      rgba(255,255,255,0.35) 0px, rgba(255,255,255,0.35) 4px,
      transparent 4px, transparent 8px);
  }

  /* vertical spacer */
  .v8  { height: 8px;  flex-shrink: 0; }
  .v16 { height: 16px; flex-shrink: 0; }
  .v24 { height: 24px; flex-shrink: 0; }
  .v32 { height: 32px; flex-shrink: 0; }
</style>
</head>
