            <div class="sub">Copilot 상시 활용</div>
          </div>
        </div>

        <!-- right branch -->
        <div class="col">
          <div style="display:flex; align-items:flex-start;">
            <div class="connector" style="height:20px;"></div>
            <div class="connector-h" style="width:60px; align-self:flex-start; margin-top:0;"></div>
