<script>
const W = 860;

// ── node widths ──
const NW = {
  root : 240,
  pillar: 240,
  exec_t: 168, exec_a: 178,
  goal_t: 185, goal_a: 185,
};

// ── row Y positions ──
const Y0 = 0;          // root top
const RH0 = 56;        // root height
const GAP_01 = 40;
const Y1 = Y0 + RH0 + GAP_01;   // pillars
const RH1 = 54;
const GAP_12 = 36;
const Y2 = Y1 + RH1 + GAP_12;   // exec
const RH2 = 56;        // exec height (two-line: 56)
const GAP_23 = 28;
const Y3 = Y2 + RH2 + GAP_23;   // goals
const RH3 = 50;

const TOTAL_H = Y3 + RH3 + 20;

// ── X centres (within 860px canvas) ──
// LEFT cluster (pillar ①): 3 exec nodes
// gap between exec nodes: 20px
const LEFT_CX  = W * 0.26;  // pillar1 centre
const RIGHT_CX = W * 0.74;  // pillar3 centre

// teal exec centres: spread around LEFT_CX
const te_gap = 20;
const te_w   = NW.exec_t;
const te_span = 3 * te_w + 2 * te_gap;
const teal_execs = [
  LEFT_CX - te_span/2 + te_w/2,
  LEFT_CX,
  LEFT_CX + te_span/2 - te_w/2,
];

// amber exec centres: 2 nodes
const ae_gap  = 24;
const ae_w    = NW.exec_a;
const ae_span = 2 * ae_w + ae_gap;
const amber_execs = [
  RIGHT_CX - ae_span/2 + ae_w/2,
  RIGHT_CX + ae_span/2 - ae_w/2,
];

// goal centres mirror exec centres
const teal_goals  = teal_execs;
const amber_goals = amber_execs;

// ── helper: set node position ──
function place(id, cx, y, w, h) {
  const el = document.getElementById(id);
  el.style.left   = (cx - w/2) + 'px';
  el.style.top    = y + 'px';
  el.style.width  = w + 'px';
  if (h) el.style.minHeight = h + 'px';
}

// measure actual rendered height after placing width
function H(id) { return document.getElementById(id).offsetHeight; }

// ── position all nodes ──
place('n0', W/2,        Y0, NW.root,   RH0);
place('n1', LEFT_CX,    Y1, NW.pillar, RH1);
place('n2', RIGHT_CX,   Y1, NW.pillar, RH1);

place('e1', teal_execs[0], Y2, NW.exec_t);
place('e2', teal_execs[1], Y2, NW.exec_t);
place('e3', teal_execs[2], Y2, NW.exec_t);
place('e4', amber_execs[0], Y2, NW.exec_a);
place('e5', amber_execs[1], Y2, NW.exec_a);

place('g1', teal_goals[0], Y3, NW.goal_t);
place('g2', teal_goals[1], Y3, NW.goal_t);
place('g3', teal_goals[2], Y3, NW.goal_t);
place('g4', amber_goals[0], Y3, NW.goal_a);
place('g5', amber_goals[1], Y3, NW.goal_a);

// set wrap height
document.getElementById('tree-wrap').style.height = TOTAL_H + 'px';

// ── draw SVG lines ──
const svg = document.getElementById('lines');
svg.setAttribute('viewBox', `0 0 ${W} ${TOTAL_H}`);
svg.setAttribute('width', W);
svg.setAttribute('height', TOTAL_H);

const SOLID_COL  = 'rgba(255,255,255,0.18)';
const DASH_TEAL  = 'rgba(29,158,117,0.55)';
const DASH_AMBER = 'rgba(186,117,23,0.55)';

function bot(y, h) { return y + h; }
function cx(id) {
  const el = document.getElementById(id);
  return parseFloat(el.style.left) + parseFloat(el.style.width)/2;
}
function top_y(id) { return parseFloat(document.getElementById(id).style.top); }
function bot_y(id) { return top_y(id) + document.getElementById(id).offsetHeight; }

function line(x1,y1,x2,y2, col, dash='') {
  const l = document.createElementNS('http://www.w3.org/2000/svg','line');
  l.setAttribute('x1',x1); l.setAttribute('y1',y1);
  l.setAttribute('x2',x2); l.setAttribute('y2',y2);
  l.setAttribute('stroke', col);
  l.setAttribute('stroke-width','1');
  if (dash) l.setAttribute('stroke-dasharray', dash);
  svg.appendChild(l);
}

function elbow(x1,y1,x2,y2, col, dash='') {
  // vertical from (x1,y1) to mid, then horizontal to x2, then vertical to y2
  const mid = (y1 + y2) / 2;
  const p = document.createElementNS('http://www.w3.org/2000/svg','path');
  p.setAttribute('d', `M${x1},${y1} L${x1},${mid} L${x2},${mid} L${x2},${y2}`);
  p.setAttribute('fill','none');
  p.setAttribute('stroke', col);
  p.setAttribute('stroke-width','1');
  if (dash) p.setAttribute('stroke-dasharray', dash);
  svg.appendChild(p);
}

// wait for layout
requestAnimationFrame(() => {
  // ── root → pillar1 (elbow) ──
  elbow(cx('n0'), bot_y('n0'), cx('n1'), top_y('n1'), SOLID_COL);

  // ── root → pillar3 (elbow) ──
  elbow(cx('n0'), bot_y('n0'), cx('n2'), top_y('n2'), SOLID_COL);

  // ── pillar1 → 3 exec nodes ──
  // vertical trunk from pillar1 bottom
  const p1b = bot_y('n1');
  const mid12 = (p1b + top_y('e1')) / 2;
  // horizontal rail at mid12
  line(cx('e1'), mid12, cx('e3'), mid12, SOLID_COL);
  // drops from rail to each exec top
  ['e1','e2','e3'].forEach(id => {
    line(cx('n1'), p1b, cx('n1'), mid12, SOLID_COL);  // trunk (drawn 3x but same)
    line(cx(id),  mid12, cx(id), top_y(id), SOLID_COL);
  });

  // ── pillar3 → 2 exec nodes ──
  const p3b = bot_y('n2');
  const mid32 = (p3b + top_y('e4')) / 2;
  line(cx('e4'), mid32, cx('e5'), mid32, SOLID_COL);
  ['e4','e5'].forEach(id => {
    line(cx('n2'), p3b, cx('n2'), mid32, SOLID_COL);
    line(cx(id),  mid32, cx(id), top_y(id), SOLID_COL);
  });

  // ── exec → goals (dashed) ──
  line(cx('e1'), bot_y('e1'), cx('g1'), top_y('g1'), DASH_TEAL,  '5 4');
  line(cx('e2'), bot_y('e2'), cx('g2'), top_y('g2'), DASH_TEAL,  '5 4');
  line(cx('e3'), bot_y('e3'), cx('g3'), top_y('g3'), DASH_TEAL,  '5 4');
  line(cx('e4'), bot_y('e4'), cx('g4'), top_y('g4'), DASH_AMBER, '5 4');
  line(cx('e5'), bot_y('e5'), cx('g5'), top_y('g5'), DASH_AMBER, '5 4');
});
</script>
