}

function elbow(x1,y1,x2,y2, col, dash='') {
  // vertical from (x1,y1) to mid, then horizontal to x2, then vertical to y2
  const mid = (y1 + y2) / 2;
  const p = document.createElementNS('http://www.w3.org/2000/svg','path');
  p.setAttribute('d', `M${x1},${y1} L${x1},${mid} L${x2},${mid} L${x2},${y2}`);
  p.setAttribute('fill','none');
  p.setAttribute('stroke', col);
  p.setAttribute('stroke-width','1');
  if (dash) p.setAttribute('stroke-dasharray', dash);
  svg.appendChild(p);
}

// wait for layout
requestAnimationFrame(() => {
  // ── root → pillar1 (elbow) ──
  elbow(cx('n0'), bot_y('n0'), cx('n1'), top_y('n1'), SOLID_COL);

  // ── root → pillar3 (elbow) ──
  elbow(cx('n0'), bot_y('n0'), cx('n2'), top_y('n2'), SOLID_COL);

  // ── pillar1 → 3 exec nodes ──
  // vertical trunk from pillar1 bottom
  const p1b = bot_y('n1');
  const mid12 = (p1b + top_y('e1')) / 2;
  // horizontal rail at mid12
  line(cx('e1'), mid12, cx('e3'), mid12, SOLID_COL);
  // drops from rail to each exec top
  ['e1','e2','e3'].forEach(id => {
    line(cx('n1'), p1b, cx('n1'), mid12, SOLID_COL);  // trunk (drawn 3x but same)
    line(cx(id),  mid12, cx(id), top_y(id), SOLID_COL);
  });

  // ── pillar3 → 2 exec nodes ──
  const p3b = bot_y('n2');
  const mid32 = (p3b + top_y('e4')) / 2;
  line(cx('e4'), mid32, cx('e5'), mid32, SOLID_COL);
  ['e4','e5'].forEach(id => {
    line(cx('n2'), p3b, cx('n2'), mid32, SOLID_COL);
    line(cx(id),  mid32, cx(id), top_y(id), SOLID_COL);
  });

  // ── exec → goals (dashed) ──
  line(cx('e1'), bot_y('e1'), cx('g1'), top_y('g1'), DASH_TEAL,  '5 4');
  line(cx('e2'), bot_y('e2'), cx('g2'), top_y('g2'), DASH_TEAL,  '5 4');
  line(cx('e3'), bot_y('e3'), cx('g3'), top_y('g3'), DASH_TEAL,  '5 4');
  line(cx('e4'), bot_y('e4'), cx('g4'), top_y('g4'), DASH_AMBER, '5 4');
  line(cx('e5'), bot_y('e5'), cx('g5'), top_y('g5'), DASH_AMBER, '5 4');
});
</script>
