{"language": "javascript", "code": "const {
  Document, Packer, Paragraph, TextRun, HeadingLevel,
  AlignmentType, BorderStyle, LevelFormat
} = require('docx');
const fs = require('fs');

// ── helpers ──────────────────────────────────────────────────────────────────
const FONT = 'Malgun Gothic';
const FONT_BODY = 16;       // 8pt → 11pt 느낌 (DXA 단위: 1pt = 2 half-pts)
const FONT_BODY_PT = 22;    // 11pt
const FONT_H1 = 36;         // 18pt
const FONT_H2 = 28;         // 14pt
const FONT_H3 = 24;         // 12pt
const COLOR_ACCENT = '4F46C8';  // 보라
const COLOR_TEAL   = '0F6E56';
const COLOR_AMBER  = '854F0B';
const COLOR_MUTED  = '6B6880';

function h1(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_1,
    spacing: { before: 480, after: 160 },
    children: [new TextRun({ text, font: FONT, size: FONT_H1, bold: true, color: COLOR_ACCENT })]
  });
}
function h2(text) {
  return new Paragraph({
    heading: HeadingLevel.HEADING_2,
    spacing: { before: 360, after: 120 },
    children: [new TextRun({ text, font: FONT, size: FONT_H2, bold: true, color: '1a1a2e' })]
  });
}
function h3(text, color = '1a1a2e') {
  return new Paragraph({
    spacing: { before: 280, after: 80 },
    children: [new TextRun({ text, font: FONT, size: FONT_H3, bold: true, color })]
  });
}
function body(text) {
  return new Paragraph({
    spacing: { before: 0, after: 140, line: 360, lineRule: 'auto' },
    children: [new TextRun({ text, font: FONT, size: FONT_BODY_PT })]
  });
}
function bodyMix(runs) {
  return new Paragraph({
    spacing: { before: 0, after: 140, line: 360, lineRule: 'auto' },
    children: runs
  });
}
function run(text, opts = {}) {
  return new TextRun({ text, font: FONT, size: FONT_BODY_PT, ...opts });
}
function bold(text, color) {
  return run(text, { bold: true, color });
}
function blank(n = 1) {
  return Array.from({ length: n }, () =>
    new Paragraph({ spacing: { before: 0, after: 0 }, children: [new TextRun('')] })
  );
}
function divider() {
  return new Paragraph({
    spacing: { before: 240, after: 240 },
    border: { bottom: { style: BorderStyle.SINGLE, size: 4, color: 'D0CCEE', space: 1 } },
    children: [new TextRun('')]
  });
}
function quote(text) {
  return new Paragraph({
    spacing: { before: 160, after: 160, line: 340, lineRule: 'auto' },
    indent: { left: 720 },
    border: { left: { style: BorderStyle.SINGLE, size: 12, color: COLOR_ACCENT, space: 16 } },
    children: [new TextRun({ text, font: FONT, size: FONT_BODY_PT, italics: true, color: '3a3560' })]
  });
}
function label(text, color = COLOR_ACCENT) {
  return new Paragraph({
    spacing: { before: 200, after: 60 },
    children: [new TextRun({ text: `[ ${text} ]`, font: FONT, size: 18, bold: true, color })]
  });
}

// ── document ─────────────────────────────────────────────────────────────────
const doc = new Document({
  styles: {
    default: {
      document: { run: { font: FONT, size: FONT_BODY_PT } }
    }
  },
  numbering: {
    config: [
      {
        reference: 'bullets',
        levels: [{
          level: 0, format: LevelFormat.BULLET, text: '–',
          alignment: AlignmentType.LEFT,
          style: { paragraph: { indent: { left: 640, hanging: 320 } },
                   run: { font: FONT, size: FONT_BODY_PT } }
        }]
      }
    ]
  },
  sections: [{
    properties: {
      page: {
        size: { width: 11906, height: 16838 },
        margin: { top: 1440, right: 1440, bottom: 1440, left: 1700 }
      }
    },
    children: [

      // ── COVER ─────────────────────────────────────────────────────────────
      new Paragraph({
        spacing: { before: 1200, after: 120 },
        children: [new TextRun({ text: 'AX 내재화', font: FONT, size: 56, bold: true, color: COLOR_ACCENT })]
      }),
      new Paragraph({
        spacing: { before: 0, after: 80 },
        children: [new TextRun({ text: '조직이 AI와 함께 일하는 방식을 배우기까지', font: FONT, size: 28, color: COLOR_MUTED })]
      }),
      new Paragraph({
        spacing: { before: 0, after: 600 },
        children: [new TextRun({ text: '— Working Backwards Essay, 2026', font: FONT, size: 20, color: 'AAAAAA', italics: true })]
      }),
      divider(),
      ...blank(2),

      // ── INTRO ─────────────────────────────────────────────────────────────
      h1('시작은 끝에서 — 2026년 말의 풍경'),

      quote('사람들은 더 이상 "AI를 써야 한다"고 생각하지 않는다. 그냥 그렇게 일하고 있을 뿐이다.'),

      body('워킹백워드(Working Backwards)는 아마존이 제품 기획에 적용한 방법론으로, 고객이 원하는 미래 상태를 먼저 선명하게 그려놓고, 거꾸로 오늘의 행동을 설계하는 사고법이다. 이 에세이는 그 문법을 빌려, 2026년 말 LG PRI EXG팀이 도달해야 할 조직의 모습에서 출발한다. 그리고 그 모습을 가능하게 하는 두 개의 축 — AI 활용도 제고와 AX 역량 고도화 — 이 어떤 논리로 연결되는지를 서술한다.'),

      body('흔히 혁신 계획은 현재 상태에서 출발한다. "지금 우리에게 부족한 것", "올해 개선해야 할 지표"를 먼저 나열하고, 그것을 채우는 방향으로 과제를 설정한다. 이 방식은 현실적이지만 한계가 있다. 현재의 관성 안에서 과제를 정의하기 때문에, 과제들이 서로 연결되지 않고 분산된다. AX 내재화는 그 함정에서 벗어나야 한다.'),

      ...blank(1),

      // ── SECTION 1 ─────────────────────────────────────────────────────────
      h1('1. 우리가 도달하려는 곳'),

      h2('1-1. 최종 상태: AI와 함께 일하는 조직'),

      body('이 모든 과제의 수렴점은 하나의 문장으로 표현된다.'),

      quote('사람이 AI를 쓰는 조직이 아니라, AI와 함께 일하는 조직.'),

      body('두 문장은 미묘하게 다르다. 전자는 도구 사용의 관점이고, 후자는 일하는 방식의 관점이다. 전자에서 AI는 선택지다. 후자에서 AI는 기본값이다. 우리가 도달하려는 곳은 후자다.'),

      body('이 상태를 측정하는 지표는 AX 성숙도 Survey 전사 평균 대비 15% 이상 향상이다. 그러나 지표 자체보다 중요한 것은 그 지표가 포착하는 실질적 변화다. 구성원들이 AI 도구를 업무에 자연스럽게 끌어들이고, 반복 작업에 시간을 쓰지 않으며, 각자의 영역에서 AI 기반의 판단과 기획을 수행하는 것. 이것이 우리가 그리는 2026년 말의 풍경이다.'),

      h2('1-2. 왜 지금인가 — 타이밍의 논리'),

      body('2026년은 두 가지 이유에서 변곡점이다. 첫째, 조직 내 AI 도구의 접근성이 처음으로 전사적 수준에 도달했다. MS Copilot의 기업 라이선스 확대, Claude Code 기반의 Agent 개발 환경 성숙, LG EP SSO 통합을 통한 보안 접근 경로 확보 — 이 조건들이 처음으로 동시에 갖춰졌다.'),

      body('둘째, HR 부서가 AI 내재화를 "교육 과제"로만 다루던 시대가 끝나고 있다. AI는 이제 인력 배치, 역량 진단, 직원 경험 설계, 학습 경로 추천에 직접 개입한다. HR이 AI를 활용할 수 있어야 HR 자체의 역할이 유지된다. EXG팀의 AX 내재화 미션은 조직 전체를 위한 것이면서, 동시에 HR이 스스로 진화하는 과정이기도 하다.'),

      ...blank(1),

      // ── SECTION 2 ─────────────────────────────────────────────────────────
      h1('2. 첫 번째 축 — AI 활용도 제고'),

      quote('사람들이 AI를 쓰지 않는 이유는 두 가지다. 할 줄 몰라서, 혹은 굳이 써야 할 이유를 못 느껴서.'),

      body('AI 활용도 제고는 이 두 가지 장벽을 동시에 허무는 과제다. 능력의 장벽을 낮추는 것이 Vibe-Coding 교육이고, 환경의 장벽을 낮추는 것이 MS Copilot 기반의 공통업무 AI 침투율 제고이며, 동기의 장벽을 구조화하는 것이 전사 인증체계 연계 역량 고도화다. 세 개의 실행 아이템은 독립적인 과제가 아니라 하나의 논리 체계를 구성한다.'),

      h2('2-1. Vibe-Coding 교육 — 비코더의 자동화 주권'),

      body('Vibe-Coding은 자연어로 AI에게 지시를 내려 코드와 자동화 도구를 만드는 방식을 말한다. 프로그래밍 지식 없이도 Lovable, Claude Code, AntiGravity 같은 도구를 활용해 실무 자동화를 구현할 수 있다. 이것이 HR 구성원들에게 의미하는 바는 단순히 "새로운 도구 하나 배우기"가 아니다.'),

      body('17년간의 HR 경험은 반복 업무의 비중이 얼마나 큰지를 잘 알고 있다. 평가 데이터 정리, 설문 집계, 보고서 초안 작성, 일정 조율. 이 작업들은 전문성과 무관하다. 그러나 그것들이 HR 담당자의 시간 대부분을 차지한다. Vibe-Coding 교육의 궁극적인 목표 지점은 "SW 백그라운드 없이도 자신의 반복 업무를 자동화하는 조직"이다. 연간 6개 과정 신설이라는 KPI는 그 방향으로의 속도 지표다.'),

      bodyMix([
        bold('교육 설계의 핵심 원칙은 세 가지다. ', COLOR_TEAL),
        run('첫째, 추상적 개념보다 당장 쓸 수 있는 실습 중심. 둘째, HR 업무 맥락에 밀착된 예제. 셋째, 교육 이후의 활용을 촉진하는 피어 학습 구조. 이 세 원칙 없이는 교육이 행동 변화로 이어지지 않는다.')
      ]),

      h2('2-2. 공통업무 AI 침투율 제고 — MS Copilot과 OneDrive'),

      body('Vibe-Coding이 "만들 수 있는 역량"을 키우는 과제라면, MS Copilot 기반 침투율 제고는 "이미 있는 도구를 쓰는 습관"을 만드는 과제다. 두 과제는 접근 방식이 다르다.'),

      body('MS Copilot은 전사 라이선스가 존재하며, OneDrive와 통합된 문서 환경에서 즉시 활용 가능하다. 이메일 초안, 회의 요약, 문서 검색, 보고서 구조화 — 이 기능들은 추가 학습 없이도 당장 일상 업무에 투입된다. 그러나 현실에서 도구는 제공되어도 습관은 생기지 않는다.'),

      body('핵심은 "AI가 없으면 불편한 환경"을 설계하는 것이다. 공통 업무 프로세스를 Copilot 활용 방식으로 재설계하고, 팀 단위 활용 루틴을 정착시키는 것이 이 과제의 실질적 내용이다. 지표는 활용률이지만, 우리가 만들고자 하는 것은 "AI가 일상이 된 업무 환경"이다.'),

      h2('2-3. 전사 인증체계 연계 역량 고도화 — 인증이 행동 유인으로'),

