const lvData = [
  { badge:'LEVEL 1', name:'AX Starter', def:'AI Tool을 업무에 활용 가능한 역량', time:'150분', zone:'전 구성원 AX 활용', zoneStyle:'background:#FEF3C7;color:#92400E;', barW:'25%', barC:'#c0421a', content:'Generative AI의 작동 원리와 한계를 이해하고, 구조화된 프롬프트로 업무 산출물(요약/초안/정리)을 안전하게 생성할 수 있다.', targets:['전 구성원'], next:'Lv.2 AX Advanced', nextDesc:'프롬프트 심화 및 RAG 기초' },
  { badge:'LEVEL 2', name:'AX Advanced', def:'AI Tool을 개인 업무에 적용하여 업무 생산성을 개선할 수 있는 역량', time:'185분', zone:'전 구성원 AX 활용', zoneStyle:'background:#FEF3C7;color:#92400E;', barW:'50%', barC:'#9e5c08', content:'Prompt Engineering 심화 기법으로 복잡한 업무를 수행하고, RAG(검색 증강 생성)의 원리를 이해하며 AI Agent의 기초 개념을 학습한다.', targets:['전 구성원'], next:'Lv.3 AX Operator', nextDesc:'Agent 역할 설계 역량 심화' },
  { badge:'LEVEL 3', name:'AX Operator', def:'도메인 지식 기반, AX 적용 영역을 선별하여 Agent 역할 설계 가능한 역량', time:'245분', zone:'AX 전문가 실행', zoneStyle:'background:#EDE9FE;color:#4C1D95;', barW:'75%', barC:'#3C3489', content:'RAG 설계, Context Engineering, Agentic AI 아키텍처 설계와 구현 역량을 갖추어 실무 Agent Workflow를 설계하고 품질을 관리한다.', targets:['AI 기획자','현업 파워유저','주니어 개발자'], next:'Lv.4 AX Expert', nextDesc:'엔터프라이즈 Agent 시스템 설계' },
  { badge:'LEVEL 4', name:'AX Expert', def:'도메인 지식 기반 업무 시스템 Agent 설계·구현 및 품질·성능 관리 역량', time:'265분', zone:'AX 전문가 실행', zoneStyle:'background:#EDE9FE;color:#4C1D95;', barW:'100%', barC:'#1a1d30', content:'RAG 품질 평가, Context Engineering 심화, Agent 오케스트레이션, 품질 관리(Test/모니터링), Agent 프로토콜(MCP/A2A), 엔터프라이즈 거버넌스.', targets:['AI/ML 엔지니어','시니어 개발자','AI CoE 담당자'], next:null, nextDesc:'' }
];

function setLv(n) {
  const d = lvData[n-1];
  document.querySelectorAll('.lv-btn').forEach((b,i)=>b.classList.toggle('active',i===n-1));
  document.getElementById('lpf').style.width = d.barW;
  document.getElementById('lpf').style.background = d.barC;
  document.getElementById('lbadge').textContent = d.badge;
  document.getElementById('lbadge').style.color = d.barC;
  document.getElementById('lname').textContent = d.name;
  document.getElementById('ldef').textContent = d.def;
  document.getElementById('ltime').textContent = d.time;
  const lz = document.getElementById('lzone');
  lz.textContent = d.zone; lz.setAttribute('style', d.zoneStyle);
  document.getElementById('lcontent').textContent = d.content;
  document.getElementById('ltargets').innerHTML = d.targets.map(t=>`<span class="lv-target-pill">${t}</span>`).join('');
  const hint = document.getElementById('lhint');
  if(d.next){ hint.style.opacity='1'; document.getElementById('lnext').textContent = d.next; hint.innerHTML = `→ 다음: <strong id="lnext">${d.next}</strong> — ${d.nextDesc}`; }
  else { hint.style.opacity='0.3'; hint.innerHTML = '최고 레벨 달성 — AX Expert'; }
}

// reveal on scroll
const obs = new IntersectionObserver(entries => {
  entries.forEach((e,i)=>{ if(e.isIntersecting) setTimeout(()=>e.target.classList.add('visible'),i*55); });
},{threshold:0.1,rootMargin:'0px 0px -30px 0px'});
document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));
</script>
