.hero-eyebrow{font-family:var(--mono);font-size:11px;letter-spacing:3px;color:rgba(90,82,213,.85);margin-bottom:24px;display:flex;align-items:center;gap:12px;}
.hero-eyebrow::before{content:'';display:block;width:28px;height:1px;background:rgba(90,82,213,.7);}
.hero h1{font-family:var(--serif);font-size:clamp(44px,6.5vw,80px);font-weight:700;line-height:1.1;letter-spacing:-1px;color:#f0ede8;margin-bottom:28px;}
.hero h1 em{font-style:normal;color:transparent;-webkit-text-stroke:1px rgba(240,237,232,.45);}
.hero-desc{font-size:15px;color:rgba(240,237,232,.5);max-width:500px;line-height:1.75;margin-bottom:48px;}
.hero-meta{display:flex;gap:0;border-top:1px solid rgba(255,255,255,.07);padding-top:28px;}
.hero-meta-item{padding:0 36px 0 0;display:flex;flex-direction:column;gap:5px;}
.hero-meta-item:first-child{padding-left:0;}
.meta-label{font-family:var(--mono);font-size:10px;letter-spacing:2px;color:rgba(255,255,255,.28);text-transform:uppercase;}
.meta-value{font-size:13px;font-weight:500;color:rgba(255,255,255,.65);}

/* SECTIONS */
.section{max-width:880px;margin:0 auto;padding:100px 40px;}
.section-wide{max-width:1060px;margin:0 auto;padding:80px 40px;}
.sec-mark{display:flex;align-items:center;gap:14px;margin-bottom:44px;}
.sec-num{font-family:var(--mono);font-size:11px;letter-spacing:2px;color:var(--muted);}
.sec-line{height:1px;flex:1;background:var(--line);}
h2.sec-title{font-family:var(--serif);font-size:clamp(26px,3.5vw,38px);font-weight:700;line-height:1.25;letter-spacing:-.4px;color:var(--ink);margin-bottom:20px;}
p.body{font-size:15px;line-height:1.9;color:#2a2d40;margin-bottom:18px;}
p.body strong{font-weight:700;color:var(--ink);}
.pull{margin:36px 0;padding:22px 30px;border-left:3px solid var(--purple);background:rgba(61,53,181,.04);border-radius:0 8px 8px 0;}
.pull p{font-family:var(--serif);font-size:17px;line-height:1.6;color:var(--ink);font-style:italic;}
.pull.teal{border-left-color:var(--teal);background:rgba(10,107,80,.04);}
.pull.amber{border-left-color:var(--amber);background:rgba(138,78,8,.04);}

/* DARK BG */
.dark-bg{background:var(--ink2);color:#f0ede8;}
.dark-bg h2.sec-title{color:#f0ede8;}
.dark-bg p.body{color:rgba(240,237,232,.68);}
.dark-bg p.body strong{color:#e8e5ff;}
.dark-bg .sec-num{color:rgba(255,255,255,.25);}
.dark-bg .sec-line{background:rgba(255,255,255,.08);}
.dark-bg .pull{background:rgba(255,255,255,.04);border-left-color:rgba(90,82,213,.7);}
.dark-bg .pull p{color:rgba(240,237,232,.78);}
.dark-bg .pull.amber{border-left-color:rgba(186,117,23,.8);background:rgba(186,117,23,.06);}

/* TINT BG */
.tint-bg{background:var(--sur2);}

/* VIZ CONTAINERS */
.viz-box{background:white;border:1px solid var(--line);border-radius:16px;overflow:hidden;margin:36px 0;}
.viz-box.dark{background:#1a1d30;border-color:rgba(255,255,255,.08);}

/* OVERVIEW SVG */
.overview-svg-wrap{padding:32px 24px 24px;}

/* COPILOT FLOW */
.cf-wrap{display:grid;grid-template-columns:1fr auto 1fr auto 1fr;align-items:center;gap:0;padding:32px 28px;}
.cf-col{display:flex;flex-direction:column;align-items:center;gap:10px;}
.cf-box{border-radius:12px;padding:20px 16px;text-align:center;width:100%;}
.cf-box.before{background:#F1EFE8;border:1px solid #D3D1C7;}
.cf-box.od{background:#E1F5EE;border:1px solid #5DCAA5;}
.cf-box.cp{background:#EEEDFE;border:1px solid #AFA9EC;}
.cf-tag{font-family:var(--mono);font-size:10px;letter-spacing:1.5px;margin-bottom:8px;}
.cf-box.before .cf-tag{color:#888780;}
.cf-box.od .cf-tag{color:#0F6E56;}
.cf-box.cp .cf-tag{color:#534AB7;}
.cf-title{font-size:15px;font-weight:700;margin-bottom:6px;}
.cf-box.before .cf-title{color:#444441;}
.cf-box.od .cf-title{color:#085041;}
.cf-box.cp .cf-title{color:#26215C;}
.cf-items{list-style:none;font-size:12px;line-height:1.75;text-align:left;}
.cf-box.before .cf-items{color:#888780;}
.cf-box.od .cf-items li::before{content:'› ';color:#1D9E75;}
.cf-box.od .cf-items{color:#085041;}
.cf-box.cp .cf-items li::before{content:'› ';color:#7F77DD;}
.cf-box.cp .cf-items{color:#26215C;}
.cf-arrow{font-size:22px;color:var(--line);padding:0 8px;display:flex;flex-direction:column;align-items:center;gap:6px;}
.cf-arrow .arr-label{font-size:10px;font-family:var(--mono);letter-spacing:1px;white-space:nowrap;}

/* TOOL PAIR */
.tool-pair{display:grid;grid-template-columns:1fr 1fr;gap:1px;background:var(--line);border-radius:12px;overflow:hidden;border:1px solid var(--line);margin:28px 0;}
.tool-card{background:white;padding:28px 24px;}
.tool-card:hover{background:#fdfcfa;}
.tool-badge{font-family:var(--mono);font-size:10px;letter-spacing:2px;margin-bottom:14px;font-weight:500;}
.tool-card.ag .tool-badge{color:var(--teal);}
.tool-card.lv .tool-badge{color:var(--purple2);}
.tool-name{font-size:18px;font-weight:700;margin-bottom:6px;}
.tool-card.ag .tool-name{color:var(--ink);}
.tool-card.lv .tool-name{color:var(--ink);}
.tool-role{font-size:12px;font-weight:600;margin-bottom:14px;padding:4px 12px;border-radius:20px;display:inline-block;}
.tool-card.ag .tool-role{background:rgba(10,107,80,.09);color:var(--teal);}
.tool-card.lv .tool-role{background:rgba(61,53,181,.09);color:var(--purple);}
.tool-desc{font-size:13.5px;line-height:1.75;color:var(--muted);}
.tool-example{margin-top:14px;padding:12px 14px;background:var(--sur2);border-radius:8px;font-size:12.5px;line-height:1.65;color:#444;}
.tool-example strong{color:var(--ink);}

/* LEVEL STEPPER */
.lv-nav{display:flex;gap:8px;padding:24px 24px 0;flex-wrap:wrap;}
.lv-btn{cursor:pointer;border:1px solid var(--line);border-radius:8px;padding:8px 16px;font-size:12px;font-family:var(--sans);background:var(--sur2);color:var(--muted);transition:.18s;font-weight:500;}
.lv-btn:hover{background:white;color:var(--ink);}
.lv-btn.active{color:white;border-color:transparent;}
.lv-btn.lv1.active{background:#c0421a;}
.lv-btn.lv2.active{background:#9e5c08;}
.lv-btn.lv3.active{background:#3C3489;}
.lv-btn.lv4.active{background:#1a1d30;}
.lv-prog-wrap{padding:16px 24px 0;}
.lv-prog{height:3px;background:var(--line);border-radius:2px;overflow:hidden;}
.lv-prog-fill{height:100%;border-radius:2px;background:#c0421a;width:25%;transition:width .4s,background .3s;}
.lv-panel{padding:24px 24px 28px;display:grid;grid-template-columns:1fr auto;gap:20px;min-height:180px;}
.lv-left{}
.lv-badge-txt{font-size:10px;font-weight:600;letter-spacing:1.5px;margin-bottom:8px;font-family:var(--mono);}
.lv-name-txt{font-size:21px;font-weight:700;color:var(--ink);margin-bottom:6px;font-family:var(--serif);}
.lv-def-txt{font-size:13px;color:var(--muted);line-height:1.55;margin-bottom:16px;}
.lv-content-txt{font-size:13.5px;line-height:1.75;color:#2a2d40;border-left:2px solid var(--line);padding-left:14px;}
.lv-right{text-align:right;min-width:160px;}
.lv-time-txt{font-size:22px;font-weight:700;color:var(--ink);font-family:var(--mono);}
.lv-time-sub{font-size:11px;color:var(--muted);margin-bottom:12px;}
.lv-zone-pill{font-size:11px;padding:4px 12px;border-radius:20px;display:inline-block;font-weight:600;}
.lv-targets{margin-top:14px;display:flex;gap:6px;flex-wrap:wrap;justify-content:flex-end;}
.lv-target-pill{font-size:11px;padding:3px 10px;border-radius:20px;background:var(--sur2);color:var(--muted);}
.lv-hint{padding:12px 24px 20px;font-size:12px;color:var(--muted);border-top:1px solid var(--line);text-align:center;}

/* CYCLE DIAGRAM */
.cycle-wrap{padding:32px 28px 28px;}
.cycle-nodes{display:flex;align-items:center;gap:0;justify-content:space-between;}
.cy-node{flex:1;display:flex;flex-direction:column;align-items:center;gap:8px;cursor:pointer;}
.cy-box{border-radius:10px;padding:14px 10px;text-align:center;width:100%;transition:transform .15s;}
.cy-box:hover{transform:translateY(-3px);}
.cy-box.teal{background:#E1F5EE;border:1px solid #5DCAA5;}
.cy-box.purple{background:#EEEDFE;border:1px solid #AFA9EC;}
.cy-box.amber{background:#FAEEDA;border:1px solid #EF9F27;}
.cy-label{font-size:13px;font-weight:700;line-height:1.3;}
.cy-box.teal .cy-label{color:#085041;}
.cy-box.purple .cy-label{color:#26215C;}
.cy-box.amber .cy-label{color:#412402;}
.cy-sub{font-size:11px;margin-top:3px;}
.cy-box.teal .cy-sub{color:#0F6E56;}
.cy-box.purple .cy-sub{color:#534AB7;}
.cy-box.amber .cy-sub{color:#633806;}
.cy-goal{font-size:11px;color:var(--muted);text-align:center;padding-top:4px;line-height:1.4;}
.cy-arrow{font-size:14px;color:var(--line);padding:0 6px;flex-shrink:0;margin-bottom:28px;}
.cy-outcome{margin-top:24px;background:#EEEDFE;border:1px solid #AFA9EC;border-radius:12px;padding:18px 24px;text-align:center;}
.cy-outcome-title{font-size:15px;font-weight:700;color:#26215C;margin-bottom:4px;}
.cy-outcome-sub{font-size:13px;color:#534AB7;}
.cy-feedback{font-size:12px;color:var(--muted);text-align:center;margin-top:12px;padding:8px;border:1px dashed rgba(61,53,181,.3);border-radius:8px;}

/* CLOSING */
.closing{background:var(--ink2);padding:100px 0 80px;}
.closing .section{text-align:center;}
.close-tag{font-family:var(--mono);font-size:10px;letter-spacing:3px;color:rgba(255,255,255,.22);margin-bottom:28px;}
.close-title{font-family:var(--serif);font-size:clamp(30px,4.5vw,52px);font-weight:700;color:#f0ede8;line-height:1.2;margin-bottom:28px;letter-spacing:-.5px;}
.close-body{font-size:14.5px;line-height:1.9;color:rgba(240,237,232,.55);max-width:560px;margin:0 auto 20px;}
.close-quote{font-family:var(--serif);font-size:19px;font-style:italic;color:rgba(90,82,213,.85);margin-top:40px;}

/* FOOTER */
footer{background:var(--ink);padding:28px 48px;display:flex;align-items:center;justify-content:space-between;border-top:1px solid rgba(255,255,255,.05);}
footer span{font-family:var(--mono);font-size:10px;color:rgba(255,255,255,.18);}

/* REVEAL */
.reveal{opacity:0;transform:translateY(20px);transition:opacity .6s ease,transform .6s ease;}
.reveal.visible{opacity:1;transform:translateY(0);}

@media(max-width:768px){
  nav{padding:0 20px;} .nav-links{display:none;}
  .hero{padding:0 28px;min-height:auto;padding-top:80px;padding-bottom:60px;}
  .section,.section-wide{padding:64px 20px;}
  .cf-wrap{grid-template-columns:1fr;} .cf-arrow{display:none;}
  .tool-pair{grid-template-columns:1fr;}
  .cycle-nodes{flex-direction:column;} .cy-arrow{display:none;}
  footer{flex-direction:column;gap:6px;text-align:center;}
}
</style>
